using Microsoft.EntityFrameworkCore;

class CosmosQuery
{
    async Task FindProductsAsync(ProductContext ctx)
    {
        // Direct Cosmos SQL — c.Discriminator is safe because we explicitly configured
        // HasDiscriminator<string>("Discriminator") to preserve the EF Core 8 property name.
        var sql = "SELECT * FROM c WHERE c.Discriminator = 'Product' AND c.Sku = @sku";

        // Sync I/O (ToList, SaveChanges, etc.) now throws in EF Core 9 Cosmos — use async.
        var products = await ctx.Products.Where(p => p.Sku == "ABC").ToListAsync();
    }
}

