2. class ProductContext : DbContext
3. {
4.     public DbSet<Product> Products => Set<Product>();
5.     protected override void OnModelCreating(ModelBuilder modelBuilder)
6.     {
7.         // HasIndex removed — throws in EF Core 9 Cosmos; manage indexing via Azure portal/Bicep.
8.         modelBuilder.Entity<Product>(entity =>
9.         {
10.             entity.ToContainer("Products");
11. 
12.             // Preserve EF Core 8 discriminator property name so existing documents
13.             // with "Discriminator": "Product" remain queryable (EF Core 9 default is "$type").
14.             entity.HasDiscriminator<string>("Discriminator");
15. 
16.             // Preserve EF Core 8 compound id format ("Product|123") so existing
17.             // documents remain accessible via FindAsync and point-reads.
18.             entity.HasRootDiscriminatorInJsonId(true);
19.         });
20.     }
21. }
22. class Product { public int Id { get; set; } public string Sku { get; set; } }
